// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('evaluation-criteria', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('evaluation-criteria', async function() {
    // Test name: evaluation-criteria
    // Step # | name | target | value
    // 1 | open | http://localhost:4200/user/evaluation-reference-pro | 
    await driver.get("http://localhost:4200/user/evaluation-reference-pro");

    // 2 | setWindowSize | 1360x768 | 
    await driver.manage().window().setRect({ width: 1360, height: 768 });

    // 3 | click | id=login_form_email | 
    await driver.findElement(By.id("login_form_email")).click();

    // 4 | type | id=login_form_email | vietnam.system
    await driver.findElement(By.id("login_form_email")).sendKeys("vietnam.system");

    // 5 | click | id=login_form_password | 
    await driver.findElement(By.id("login_form_password")).click();

    // 6 | type | id=login_form_password | 12345678
    await driver.findElement(By.id("login_form_password")).sendKeys("12345678");

    // 7 | click | css=.ant-btn | 
    await driver.findElement(By.css(".ant-btn")).click();

    // 8 | mouseOver | css=.ant-btn | 
    {
      const element = await driver.findElement(By.css(".ant-btn"));
      await driver.actions({ bridge: true }).moveToElement(element).perform();
    }

    // 9 | assertText | xpath=//div[@id='root']/section/section/main/h3 | 評価基準
    assert(await driver.findElement(By.xpath("//div[@id=\'root\']/section/section/main/h3")).getText() == "評価基準");

    // 10 | executeScript | return getComputedStyle(document.getElementsByClassName("ant-typography")[0]).color | title_color
    vars["title_color"] = await driver.executeScript("return getComputedStyle(document.getElementsByClassName(\"ant-typography\")[0]).color");

    // 11 | assert | title_color | rgb(0, 135, 77)
    assert(vars["title_color"].toString() == "rgb(0, 135, 77)");

    // 12 | assertText | xpath=//div[@id='root']/section/section/main/form/div/div/div/label | 評価期間
    assert(await driver.findElement(By.xpath("//div[@id=\'root\']/section/section/main/form/div/div/div/label")).getText() == "評価期間");

    // 13 | assertText | xpath=//div[@id='root']/section/section/main/form/div/div/div/label | 評価期間
    assert(await driver.findElement(By.xpath("//div[@id=\'root\']/section/section/main/form/div/div/div/label")).getText() == "評価期間");

    // 14 | assertText | xpath=//div[@id='root']/section/section/main/form/div[2]/div/div/label | 等級
    assert(await driver.findElement(By.xpath("//div[@id=\'root\']/section/section/main/form/div[2]/div/div/label")).getText() == "等級");

    // 15 | assertText | css=div:nth-child(3) > .ant-typography:nth-child(1) | 評価基準
    assert(await driver.findElement(By.css("div:nth-child(3) > .ant-typography:nth-child(1)")).getText() == "評価基準");

    // 16 | assertText | css=div:nth-child(4) > .ant-typography:nth-child(1) | 注意事項
    assert(await driver.findElement(By.css("div:nth-child(4) > .ant-typography:nth-child(1)")).getText() == "注意事項");

    // 17 | click | css=.ant-btn-primary > span | 
    await driver.findElement(By.css(".ant-btn-primary > span")).click();

    // 18 | mouseOver | css=.ant-btn-primary > span | 
    {
      const element = await driver.findElement(By.css(".ant-btn-primary > span"));
      await driver.actions({ bridge: true }).moveToElement(element).perform();
    }

    // 19 | mouseOut | css=.ant-btn-sm > span | 
    {
      const element = await driver.findElement(By.CSS_SELECTOR, "body");
      await driver.actions({ bridge: true }).moveToElement(element, 0, 0).perform();
    }

    // 20 | click | css=.ant-btn-primary:nth-child(2) > span | 
    await driver.findElement(By.css(".ant-btn-primary:nth-child(2) > span")).click();

    // 21 | close |  | 
    await driver.close();
  });
});
